import java.sql.*;

public class UserRepository {
    // Database URL with credentials (never hardcode in real code)
    private static final String URL = "jdbc:postgresql://localhost:5432/mydb";

    public void findUsersAboveAge(int minAge) {
        // try-with-resources auto-closes connection, stmt, results
        String sql = "SELECT name, age FROM users WHERE age > ?";

        try (Connection conn = DriverManager.getConnection(URL, "admin", "pass");
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            // Set parameters safely (prevents SQL injection)
            stmt.setInt(1, minAge);
            ResultSet rs = stmt.executeQuery();

            // Iterate through result rows
            while (rs.next()) {
                String name = rs.getString("name");
                int age = rs.getInt("age");
                System.out.println(name + " - " + age);
            }
        } catch (SQLException e) {
            System.err.println("Database error: " + e.getMessage());
        }
    }
}
// Expected: prints all users older than minAge
